$j$[{"en": "I misunderstood the question.", "pt": "Entendi a pergunta errado."}, {"en": "Don't overreact.", "pt": "Nao exagere na reacao."}, {"en": "They disagreed with me.", "pt": "Discordaram de mim."}]$j$::jsonb,
