('C1', 4025, $$Suavizar opinioes (hedging)$$, $$It seems / I would say$$, $$🪶$$,
$$Em ingles formal/educado, suavizamos afirmacoes: 'It seems that...', 'It tends to...', 'I would say...', 'It might be...', 'to some extent', 'apparently'. Soa menos categorico e mais profissional.$$,
$$Evite afirmar 100%: prefira 'it appears' a 'it is'.$$,
$j$[{"en": "It seems to be a good idea.", "pt": "Parece ser uma boa ideia."}, {"en": "I would say it's too expensive.", "pt": "Eu diria que e caro demais."}, {"en": "This tends to happen often.", "pt": "Isso costuma acontecer com frequencia."}]$j$::jsonb,
$j$[{"q": "Suaviza 'This is wrong':", "ctx": "", "opts": ["This may not be quite right", "This is totally wrong", "Wrong!", "No way"], "ans": 0, "exp": "Hedging educado."}, {"q": "'I would say' serve para:", "ctx": "", "opts": ["dar opiniao com cautela", "ordenar", "negar tudo", "perguntar"], "ans": 0, "exp": "Opiniao suave."}, {"q": "'It tends to' indica:", "ctx": "", "opts": ["tendencia (nao regra fixa)", "certeza absoluta", "proibicao", "passado"], "ans": 0, "exp": "Tendencia."}, {"q": "'To some extent' =", "ctx": "", "opts": ["em certa medida", "totalmente", "nunca", "de novo"], "ans": 0, "exp": "Parcialmente."}, {"q": "Hedging deixa o discurso:", "ctx": "", "opts": ["mais educado/profissional", "grosseiro", "infantil", "confuso"], "ans": 0, "exp": "Educado."}, {"q": "Mais cauteloso:", "ctx": "", "opts": ["It appears to be true", "It is definitely true", "Obviously true", "100% true"], "ans": 0, "exp": "'appears' suaviza."}]$j$::jsonb),

